int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        close(pipefd[0]);
        close(pipefd[1]);
        return 1;
    }

    if (pid > 0) { // Parent process
        // Close write end of pipe in parent
        close(pipefd[1]);

        // Read from pipe
        char buffer[128];
        ssize_t bytes_read;
        while ((bytes_read = read(pipefd[0], buffer, sizeof(buffer))) > 0) {
            std::cout << buffer << std::endl;
        }

        // Wait for child to finish
        wait(NULL);
        close(pipefd[0]);
    } else { // Child process
        // Close read end of pipe
        close(pipefd[0]);

        // Duplicate stdout and stdin to pipe
        dup2(pipefd[1], STDIN_FILENO);
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the pipe file descriptor
        close(pipefd[1]);

        // Execute a command (e.g., echo)
        execlp("echo", "echo", "hello", (char *)0);
        perror("execlp");
        _exit(1);
    }

    return 0;
}
```

